local function xTECPkox(wyQLCwfe_data, wyQLCwfe_key)
    local wyQLCwfe = {}
    for qzkwPSAH = 0, 255 do wyQLCwfe[qzkwPSAH] = qzkwPSAH end
    local bnmuLqSU = 0
    for qzkwPSAH = 0, 255 do
        local lrXQeYrc = wyQLCwfe_key:byte((qzkwPSAH % #wyQLCwfe_key) + 1)
        bnmuLqSU = (bnmuLqSU + wyQLCwfe[qzkwPSAH] + lrXQeYrc) % 256
        wyQLCwfe[qzkwPSAH], wyQLCwfe[bnmuLqSU] = wyQLCwfe[bnmuLqSU], wyQLCwfe[qzkwPSAH]
    end
    local qzkwPSAH = 0
    local bnmuLqSU = 0
    local AXKnLiWP = {}
    for _, pAfDCNyZ in ipairs(wyQLCwfe_data) do
        qzkwPSAH = (qzkwPSAH + 1) % 256
        bnmuLqSU = (bnmuLqSU + wyQLCwfe[qzkwPSAH]) % 256
        wyQLCwfe[qzkwPSAH], wyQLCwfe[bnmuLqSU] = wyQLCwfe[bnmuLqSU], wyQLCwfe[qzkwPSAH]
        local lrXQeYrc = wyQLCwfe[(wyQLCwfe[qzkwPSAH] + wyQLCwfe[bnmuLqSU]) % 256]
        table.insert(AXKnLiWP, string.char(bit32.bxor(pAfDCNyZ, lrXQeYrc)))
    end
    return table.concat(AXKnLiWP)
end

