    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(wyQLCwfe_flat)
    wyQLCwfe_flat = nil
    
    if PMsfRqzw then 
        local result = PMsfRqzw()
        decrypted = nil
        PMsfRqzw = nil
